                writer.WritePropertyName("introspection_endpoint_auth_methods_supported");
                JsonSerializer.Serialize(writer, oAuthServerMetadata.IntrospectionEndpointAuthMethodsSupported, jsonSerializerOptions);
            }
        }
    }
}
